                WriteLiteral(@"
    <script>
        var procedures  = [];
        var procCounter = 0;

        function onMasterSelect() {
            var sel = document.getElementById('ddlNursingMaster');
            var opt = sel.options[sel.selectedIndex];
            if (opt && opt.value) {
                document.getElementById('txtProcCharge').value  = opt.dataset.charge || 0;
                document.getElementById('txtCustomProcedure').value = '';
            }
        }

        function addProcedure() {
            var sel    = document.getElementById('ddlNursingMaster');
            var custom = document.getElementById('txtCustomProcedure').value.trim();
            var qty    = parseFloat(document.getElementById('txtProcQty').value) || 1;
            var charge = parseFloat(document.getElementById('txtProcCharge').value) || 0;
            var nurseSel = document.getElementById('ddlNurse');
            var nurseId  = nurseSel.value || '';
            var nurseName = nurseId ? nurseSel.options[nurseSel.sel");
                WriteLiteral(@"ectedIndex].text : '-';

            if (!sel.value && !custom) {
                alert('Select from list or enter custom procedure name');
                return;
            }
            if (charge <= 0) {
                alert('Please enter charge amount');
                return;
            }

            var opt      = sel.options[sel.selectedIndex];
            var name     = sel.value ? opt.dataset.name : custom;
            var type     = sel.value ? opt.dataset.type : 'PerProcedure';
            var masterId = sel.value ? parseInt(sel.value) : null;
            var total    = qty * charge;

            procCounter++;
            procedures.push({ id: procCounter, masterId, name, type, qty, charge, total, nurseId, nurseName });

            var noRow = document.getElementById('noProcRow');
            if (noRow) noRow.remove();

            document.getElementById('proceduresBody').insertAdjacentHTML('beforeend', `
                <tr id=""procRow_${procCounter}"">
           ");
                WriteLiteral(@"         <td>${procCounter}</td>
                    <td><strong>${name}</strong></td>
                    <td><span class=""badge ${type === 'PerDay' ? 'bg-info' : 'bg-warning text-dark'}"">${type}</span></td>
                    <td>${nurseName}</td>
                    <td>${qty}</td>
                    <td class=""text-end"">₹${charge.toFixed(2)}</td>
                    <td class=""text-end""><strong>₹${total.toFixed(2)}</strong></td>
                    <td>
                        <button type=""button"" class=""btn btn-sm btn-danger""
